import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct ClockIntent: AppIntent {
    static var title: LocalizedStringResource = "Clock"
    @Parameter(title: "Clock Style") var clockStyle: String
}

struct ClockWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "ClockWidget",
            intent: ClockIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.clockStyle) {
                    content.add(model)
                }
            }
        }
    }
}

